// DTOs are thin, untransformed shapes matching API responses
const ArticleDTOSchema = z.object({
  id: z.string(),
  attributes: z.object({
    title: z.string(),
    slug: z.string(),
    content: z.string(),
    publishedAt: z.string().datetime(),
  }),
});

type ArticleDTO = z.infer<typeof ArticleDTOSchema>;

// Validation happens at import time
const data = JSON.parse(response.body);
const validDTO = ArticleDTOSchema.parse(data); // Throws if invalid

// Domain Model (internal representation)
interface Article {
  id: string;
  title: string;
  slug: string;
  content: string;
  excerpt: string;        // ← Computed from content
  readTime: string;       // ← Computed from content length
  publishedAt: Date;      // ← Parsed from string
}

// Mapper with explicit transformation logic
function mapArticleDTO(dto: ArticleDTO): Article {
  return {
    id: dto.id,
    title: dto.attributes.title,
    slug: dto.attributes.slug,
    content: dto.attributes.content,
    excerpt: computeExcerpt(dto.attributes.content),
    readTime: computeReadTime(dto.attributes.content),
    publishedAt: new Date(dto.attributes.publishedAt),
  };
}

// Result is fully typed and populated, no undefined values

// Repository interface (contract)
interface ArticleRepository {
  getBySlug(slug: string): Promise<Article | null>;
  listAll(): Promise<Article[]>;
  listByCategory(category: string): Promise<Article[]>;
}

// Page uses the interface, not the implementation
const articleRepo: ArticleRepository = { /* implementation */ };

// Every method that exists on the interface is type-checked
const article = await articleRepo.getBySlug('my-article'); // ✅ Works
await articleRepo.nonExistentMethod(); // ❌ Compile error

// Component defines required props
interface ArticleViewProps {
  article: Article;
  relatedArticles: Article[];
  className?: string;
}

function ArticleView({ article, relatedArticles, className }: ArticleViewProps) {
  return (
    <article>
      <h1>{article.title}</h1>
      <p>{article.excerpt}</p>
      {/* relatedArticles is guaranteed to be Article[] */}
    </article>
  );
}

// Page passing props
export default async function ArticlePage({ params }) {
  const article = await articleRepo.getBySlug(params.slug);
  const related = await articleRepo.listRelated(params.slug);

  return (
    <ArticleView 
      article={article}              // ✅ Type matches
      relatedArticles={related}      // ✅ Type matches
      className='prose'              // ✅ Optional, type matches
    />
  );
}
